import sys, re
from html.parser import HTMLParser
class ML(HTMLParser):
    def __init__(self):
        super().__init__()
        self.items = []
        self.in_item = False
        self.in_title = False
        self.current_title = ''
    def handle_starttag(self, t, a):
        if t == 'item': self.in_item = True
        elif t == 'title' and self.in_item: self.in_title = True
    def handle_endtag(self, t):
        if t == 'title' and self.in_title: 
            self.in_title = False
            self.items.append(self.current_title.strip())
            self.current_title = ''
        elif t == 'item': self.in_item = False
    def handle_data(self, d):
        if self.in_title: self.current_title += d
p = ML()
p.feed(sys.stdin.read())
for i, t in enumerate(p.items[:6]): print(f\"{i+1}. {t}\")
